/* DIT backward: pointer-swap trick (Frigo & Johnson).
 * Swapping re↔im on input+output converts forward DFT to backward. */
__attribute__((target("avx512f,fma")))
static inline void
radix25_tw_dag_dit_bwd_avx512(
    const double * __restrict__ in_re, const double * __restrict__ in_im,
    double * __restrict__ out_re, double * __restrict__ out_im,
    const double * __restrict__ tw_re, const double * __restrict__ tw_im,
    size_t K)
{
    radix25_tw_dag_dit_fwd_avx512(in_im, in_re, out_im, out_re, tw_re, tw_im, K);
}

